import type { Meta, StoryObj } from '@storybook/angular';
import { NgxSmartComponents } from './ngx-smart-components';
import { expect } from 'storybook/test';

const meta: Meta<NgxSmartComponents> = {
  component: NgxSmartComponents,
  title: 'NgxSmartComponents',
};
export default meta;

type Story = StoryObj<NgxSmartComponents>;

export const Primary: Story = {
  args: {},
};

export const Heading: Story = {
  args: {},
  play: async ({ canvas }) => {
    await expect(canvas.getByText(/NgxSmartComponents works!/gi)).toBeTruthy();
  },
};

